// Safe wrappers around localStorage and JSON parsing.
// All access is guarded for SSR / privacy-mode browsers and never throws.

const isBrowser = typeof window !== 'undefined' && typeof window.localStorage !== 'undefined';

export const safeJsonParse = <T,>(raw: string | null | undefined, fallback: T): T => {
  if (raw == null || raw === '') return fallback;
  try {
    return JSON.parse(raw) as T;
  } catch {
    return fallback;
  }
};

export const storage = {
  get<T>(key: string, fallback: T): T {
    if (!isBrowser) return fallback;
    try {
      return safeJsonParse<T>(localStorage.getItem(key), fallback);
    } catch {
      return fallback;
    }
  },

  getString(key: string): string | null {
    if (!isBrowser) return null;
    try {
      return localStorage.getItem(key);
    } catch {
      return null;
    }
  },

  set<T>(key: string, value: T): void {
    if (!isBrowser) return;
    try {
      localStorage.setItem(key, JSON.stringify(value));
    } catch {
      // Ignore: quota exceeded / disabled storage.
    }
  },

  remove(key: string): void {
    if (!isBrowser) return;
    try {
      localStorage.removeItem(key);
    } catch {
      // Ignore.
    }
  },
};
