import { Roles } from "./api.types";
import { ProfileResult } from "./profile.types";

// New backend TokenResponse: { token, expiresAt (ISO date), profile (ProfileView), isProfileComplete }.
export type TokenResponse = {
    token: string;
    expiresAt: string;
    profile: ProfileResult;
    isProfileComplete: boolean;
};

// Legacy auth payload kept in localStorage so existing consumers keep working unchanged.
// Built from TokenResponse via AdaptTokenResponse() at sign-in time.
export type AuthTokenResult = {
    tokenType: string;
    expiresIn: number;
    extExpiresIn: number;
    expiresOn: number;        // unix seconds
    notBefore: number;
    resource: string;         // user email
    accessToken: string;
    name: string;
    userId: string;
    roles: Roles[];
    xv: boolean;              // profile complete flag
};

export type CreateTokenPayload = {
    emailOrPhone: string;
    otp: string;
};

export type CreateOtpPayload = {
    emailOrPhone: string;
};

export type ResetPayload = {
    emailOrPhone: string;
};

// Adapter: TokenResponse (new API) → AuthTokenResult (legacy storage shape).
export const AdaptTokenResponse = (tr: TokenResponse): AuthTokenResult => {
    const expiresOnSec = Math.floor(new Date(tr.expiresAt).getTime() / 1000);
    const profile = tr.profile;
    return {
        tokenType: 'Bearer',
        expiresIn: 0,
        extExpiresIn: 0,
        expiresOn: expiresOnSec,
        notBefore: 0,
        resource: profile?.email ?? '',
        accessToken: tr.token,
        name: profile?.name ?? '',
        userId: profile?.id ?? '',
        roles: (profile?.roles as Roles[]) ?? [],
        xv: !!tr.isProfileComplete,
    };
};
