import { Roles } from "../types/api.types";
import { AuthTokenResult, TokenResponse, AdaptTokenResponse } from "../types/auth.types";
import { storage } from "./storage";

const AUTH_KEY = 'authData';
const EMPTY: AuthTokenResult = {} as AuthTokenResult;

export const SetAccessTokenData = (authTokenResult: AuthTokenResult): void => {
	storage.set(AUTH_KEY, authTokenResult);
};

// Convenience: persist a fresh token straight from the new TokenResponse envelope.
export const SetAccessTokenFromResponse = (tr: TokenResponse): AuthTokenResult => {
	const adapted = AdaptTokenResponse(tr);
	SetAccessTokenData(adapted);
	return adapted;
};

export const ClearAccessTokenData = (): void => {
	storage.remove(AUTH_KEY);
};

export const GetAccessTokenData = (): AuthTokenResult => {
	return storage.get<AuthTokenResult>(AUTH_KEY, EMPTY);
};

export const GetAccessToken = (): string => GetAccessTokenData()?.accessToken ?? '';

export const IsTokenValid = (): boolean => {
	const t = GetAccessTokenData();
	if (!t || !t.accessToken) return false;
	const nowSec = Date.now() / 1000;
	if (t.expiresOn && t.expiresOn > nowSec) return true;
	storage.remove(AUTH_KEY);
	return false;
};

export const GetUserRoles = (): Roles[] => GetAccessTokenData()?.roles ?? [];

export const GetUserEmail = (): string => GetAccessTokenData()?.resource ?? '';

export const GetUserName = (): string => GetAccessTokenData()?.name ?? '';

export const GetUserId = (): string => GetAccessTokenData()?.userId ?? '';

export const IsProfileComplete = (): boolean => GetAccessTokenData()?.xv === true;

export const SetProfileComplete = (): void => {
	const t = GetAccessTokenData();
	if (t && t.accessToken) {
		t.xv = true;
		storage.set(AUTH_KEY, t);
	}
};
